#!/usr/bin/env node
/**
 * Lightweight self-host seed loop for a single Render free web service.
 *
 * It only writes data fetched from public/keyless sources or generated by
 * existing local API handlers. Missing credentialed providers remain honestly
 * unavailable/degraded.
 */

const { spawn } = require('child_process');

const REDIS_URL = process.env.UPSTASH_REDIS_REST_URL || 'http://127.0.0.1:46279';
const REDIS_TOKEN = process.env.UPSTASH_REDIS_REST_TOKEN || 'local-self-hosted';
const API_PORT = process.env.LOCAL_API_PORT || '46123';
const API_TOKEN = process.env.LOCAL_API_TOKEN || '';
const API_BASE = `http://127.0.0.1:${API_PORT}`;
const UA = 'Varun World Monitor self-hosted seeder/1.0';

const MINUTE = 60_000;
const HOUR = 60 * MINUTE;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function redis(command) {
  const resp = await fetch(`${REDIS_URL}/`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${REDIS_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify(command),
    signal: AbortSignal.timeout(15_000),
  });
  if (!resp.ok) throw new Error(`local redis HTTP ${resp.status}`);
  return resp.json();
}

async function setJson(key, value, ttlSeconds) {
  await redis(['SET', key, JSON.stringify(value), 'EX', String(ttlSeconds)]);
}

async function writeMeta(key, count, sourceVersion, ttlSeconds, maxContentAgeMin, newestItemAt) {
  const meta = { fetchedAt: Date.now(), recordCount: count, sourceVersion };
  if (maxContentAgeMin) {
    meta.maxContentAgeMin = maxContentAgeMin;
    meta.newestItemAt = newestItemAt || null;
  }
  await setJson(key, meta, ttlSeconds);
}

async function getJson(url, timeoutMs = 20_000) {
  const resp = await fetch(url, {
    headers: { 'User-Agent': UA, Accept: 'application/json' },
    signal: AbortSignal.timeout(timeoutMs),
  });
  if (!resp.ok) throw new Error(`${url} HTTP ${resp.status}`);
  return resp.json();
}

function validUrl(value) {
  try {
    const url = new URL(String(value || ''));
    return url.protocol === 'http:' || url.protocol === 'https:';
  } catch {
    return false;
  }
}

async function seedEarthquakes() {
  const data = await getJson('https://earthquake.usgs.gov/earthquakes/feed/v1.0/summary/4.5_week.geojson');
  const earthquakes = (data.features || []).map((f) => {
    const [longitude, latitude, depthKm] = f.geometry?.coordinates || [];
    return {
      id: String(f.id || f.properties?.code || ''),
      place: String(f.properties?.place || 'Unknown'),
      magnitude: Number(f.properties?.mag || 0),
      depthKm: Number(depthKm || 0),
      location: { latitude: Number(latitude || 0), longitude: Number(longitude || 0) },
      occurredAt: Number(f.properties?.time || 0),
      sourceUrl: String(f.properties?.url || ''),
    };
  }).filter((e) => e.id && Number.isFinite(e.occurredAt));
  await setJson('seismology:earthquakes:v1', { earthquakes }, 3600);
  await writeMeta('seed-meta:seismology:earthquakes', earthquakes.length, 'usgs-4.5-week-selfhost', 86400 * 7);
  return earthquakes.length;
}

async function seedNaturalEvents() {
  const data = await getJson('https://eonet.gsfc.nasa.gov/api/v3/events?days=30&status=open');
  const events = (data.events || []).map((e) => ({
    id: String(e.id || ''),
    title: String(e.title || ''),
    description: String(e.description || ''),
    categories: (e.categories || []).map((c) => c.title || c.id).filter(Boolean),
    sources: (e.sources || []).filter((s) => validUrl(s.url)),
    geometries: Array.isArray(e.geometry) ? e.geometry : [],
  })).filter((e) => e.id && e.title);
  await setJson('natural:events:v1', { events }, 6 * 3600);
  await writeMeta('seed-meta:natural:events', events.length, 'nasa-eonet-selfhost', 86400 * 7);
  return events.length;
}

const GDELT_TOPICS = [
  { id: 'military', query: '(military exercise OR troop deployment OR airstrike OR "naval exercise") sourcelang:eng' },
  { id: 'cyber', query: '(cyberattack OR ransomware OR hacking OR "data breach" OR APT) sourcelang:eng' },
  { id: 'nuclear', query: '(nuclear OR uranium enrichment OR IAEA OR "nuclear weapon" OR plutonium) sourcelang:eng' },
  { id: 'sanctions', query: '(sanctions OR embargo OR "trade war" OR tariff OR "economic pressure") sourcelang:eng' },
  { id: 'intelligence', query: '(espionage OR spy OR "intelligence agency" OR covert OR surveillance) sourcelang:eng' },
  { id: 'maritime', query: '(naval blockade OR piracy OR "strait of hormuz" OR "south china sea" OR warship) sourcelang:eng' },
];

async function fetchGdeltTopic(topic) {
  const url = new URL('https://api.gdeltproject.org/api/v2/doc/doc');
  url.searchParams.set('query', topic.query);
  url.searchParams.set('mode', 'artlist');
  url.searchParams.set('maxrecords', '10');
  url.searchParams.set('format', 'json');
  url.searchParams.set('sort', 'date');
  url.searchParams.set('timespan', '24h');
  const data = await getJson(url.toString(), 25_000);
  const articles = (data.articles || []).map((raw) => ({
    title: String(raw.title || '').slice(0, 500),
    url: String(raw.url || ''),
    source: String(raw.domain || raw.source?.domain || '').slice(0, 200),
    date: String(raw.seendate || ''),
    image: validUrl(raw.socialimage) ? raw.socialimage : '',
    language: String(raw.language || ''),
    tone: typeof raw.tone === 'number' ? raw.tone : 0,
  })).filter((a) => a.title && validUrl(a.url));
  return { id: topic.id, articles, fetchedAt: new Date().toISOString() };
}

async function seedGdeltIntel() {
  const topics = [];
  for (const topic of GDELT_TOPICS) {
    try {
      topics.push(await fetchGdeltTopic(topic));
    } catch (err) {
      console.warn(`[self-seed] GDELT ${topic.id} failed:`, err?.message || err);
      topics.push({ id: topic.id, articles: [], fetchedAt: new Date().toISOString() });
    }
    await sleep(3_000);
  }
  const populated = topics.filter((t) => t.articles.length > 0).length;
  if (populated === 0) throw new Error('GDELT returned no populated topics');
  const payload = { topics, fetchedAt: new Date().toISOString() };
  await setJson('intelligence:gdelt-intel:v1', payload, 24 * 3600);
  await writeMeta('seed-meta:intelligence:gdelt-intel', populated, 'gdelt-doc-v2-selfhost', 86400 * 7, 720, Date.now());
  return topics.reduce((sum, t) => sum + t.articles.length, 0);
}

async function seedInsightsFromGdelt() {
  const topicsResp = await fetch(`${REDIS_URL}/get/${encodeURIComponent('intelligence:gdelt-intel:v1')}`, {
    headers: { Authorization: `Bearer ${REDIS_TOKEN}` },
  });
  const stored = await topicsResp.json();
  const gdelt = stored.result ? JSON.parse(stored.result) : null;
  const articles = (gdelt?.topics || []).flatMap((topic) =>
    (topic.articles || []).map((article) => ({ ...article, topic: topic.id })),
  ).filter((a) => a.title && a.url);
  if (articles.length === 0) throw new Error('no GDELT articles for insights');
  const topStories = articles.slice(0, 12).map((a) => ({
    primaryTitle: a.title,
    primarySource: a.source || 'GDELT',
    primaryLink: a.url,
    pubDate: a.date || new Date().toISOString(),
    sourceCount: 1,
    uniqueSourceCount: 1,
    sources: [{ title: a.title, source: a.source || 'GDELT', url: a.url, publishedAt: a.date || undefined }],
    memberTitles: [a.title],
    velocity: { level: 'normal', sourcesPerHour: 0 },
    isAlert: ['military', 'cyber', 'nuclear', 'sanctions'].includes(a.topic),
    category: a.topic,
    threatLevel: ['military', 'nuclear'].includes(a.topic) ? 'high' : 'medium',
    countryCode: null,
  }));
  const briefTitles = topStories.slice(0, 3).map((s) => s.primaryTitle).join('; ');
  const payload = {
    worldBrief: `Latest monitored open-source intelligence headlines include: ${briefTitles}.`,
    worldBriefSources: topStories.slice(0, 3).flatMap((s) => s.sources),
    briefProvider: 'self-hosted-extractive',
    briefModel: 'gdelt-headline-summary',
    status: 'degraded',
    topStories,
    generatedAt: new Date().toISOString(),
    clusterCount: topStories.length,
    multiSourceCount: 0,
    fastMovingCount: 0,
    importanceSignals: { mode: 'self-hosted-keyless', note: 'Extractive summary from GDELT articles; no LLM configured.' },
  };
  await setJson('news:insights:v1', payload, 3 * 3600);
  await writeMeta('seed-meta:news:insights', topStories.length, 'gdelt-extractive-selfhost', 86400 * 7, 30, Date.now());
  return topStories.length;
}

async function warmRiskScores() {
  const headers = API_TOKEN ? { Authorization: `Bearer ${API_TOKEN}` } : {};
  const resp = await fetch(`${API_BASE}/api/intelligence/v1/get-risk-scores`, {
    headers,
    signal: AbortSignal.timeout(60_000),
  });
  if (!resp.ok) throw new Error(`risk scores HTTP ${resp.status}`);
  const data = await resp.json();
  return data?.ciiScores?.length || 0;
}

function runNodeScript(script, timeoutMs) {
  return new Promise((resolve, reject) => {
    const child = spawn(process.execPath, [`/app/scripts/${script}`], {
      cwd: '/app',
      env: process.env,
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    let output = '';
    const timer = setTimeout(() => {
      child.kill('SIGTERM');
      reject(new Error(`${script} timed out`));
    }, timeoutMs);
    child.stdout.on('data', (d) => { output += d.toString(); });
    child.stderr.on('data', (d) => { output += d.toString(); });
    child.on('exit', (code) => {
      clearTimeout(timer);
      if (code === 0) resolve(output.trim());
      else reject(new Error(`${script} exited ${code}: ${output.slice(-500)}`));
    });
  });
}

async function runJob(name, fn) {
  try {
    const count = await fn();
    console.log(`[self-seed] ${name}: ok (${count})`);
  } catch (err) {
    console.warn(`[self-seed] ${name}: degraded (${err?.message || err})`);
  }
}

async function once() {
  await runJob('earthquakes', seedEarthquakes);
  await runJob('natural-events', seedNaturalEvents);
  await runJob('gdelt-intel', seedGdeltIntel);
  await runJob('insights', seedInsightsFromGdelt);
  await runJob('risk-scores', warmRiskScores);
  await runJob('national-debt', () => runNodeScript('seed-national-debt.mjs', 5 * MINUTE).then(() => 'seeded'));
}

async function main() {
  console.log('[self-seed] starting lightweight single-container seed loop');
  await sleep(Number(process.env.SELF_HOSTED_SEED_START_DELAY_MS || 20_000));
  await once();
  setInterval(() => {
    once().catch((err) => console.warn('[self-seed] loop failed:', err?.message || err));
  }, Number(process.env.SELF_HOSTED_SEED_INTERVAL_MS || 30 * MINUTE)).unref?.();
}

main().catch((err) => {
  console.error('[self-seed] fatal:', err?.message || err);
  process.exit(1);
});
